INSERT INTO public.phases (number, slug, title, subtitle, description, category, icon, tier_required, sort_order, content) VALUES
(1, 'business-idea', 'Business Idea & Validation', 'Is your health business viable?', 'Validate your healthcare business concept, identify your target market, and understand the regulatory landscape before investing time and money.', 'Foundation', 'Lightbulb', 'free', 1, '{"overview": "Every successful health business starts with a validated idea. This phase helps you assess market demand, understand your competition, and confirm your concept is viable before you invest.", "checklist": ["Define your target patient demographic", "Research local competition and gaps", "Validate demand (surveys, waitlists, social media)", "Identify your unique value proposition", "Understand regulatory requirements for your profession", "Calculate minimum viable patient volume"], "mistakes": ["Starting without understanding AHPRA advertising rules", "Assuming demand exists without validation", "Copying a capital city model in a regional area"], "tips": ["Talk to 20 potential patients before spending a dollar", "Join profession-specific Facebook groups to gauge demand", "Check HealthDirect for service gaps in your area"]}'),
(2, 'legal-structure', 'Legal Structure & Registration', 'ABN, company, trust — get it right first', 'Choose the right legal structure, register your business, and set up the foundations for compliance and asset protection.', 'Foundation', 'Scale', 'free', 2, '{"overview": "Your legal structure affects tax, liability, and future growth. Get professional advice early — restructuring later is expensive and disruptive.", "checklist": ["Choose structure: sole trader, company, trust, or partnership", "Register ABN and business name", "Register for GST (if revenue > $75K)", "Obtain professional indemnity insurance", "Set up a business bank account", "Register domain name"], "mistakes": ["Operating as sole trader without understanding personal liability", "Not getting a trust structure reviewed by a health-specialist accountant", "Forgetting to separate personal and business banking from day one"], "tips": ["A health-specialist accountant will save you more than they cost", "Company structures offer better asset protection but more compliance", "Register your .com.au domain early — they get taken quickly"]}'),
(3, 'registration-credentialing', 'Registration & Credentialing', 'AHPRA, Medicare, insurance — the non-negotiables', 'Complete all professional registrations, Medicare provider numbers, and insurance requirements before seeing your first patient.', 'Foundation', 'ShieldCheck', 'free', 3, '{"overview": "Without proper registration and credentialing, you cannot legally practice or bill. This phase covers every registration you need.", "checklist": ["Confirm AHPRA registration is current and endorsed correctly", "Apply for Medicare provider number (location-specific)", "Apply for PBS prescriber number (if applicable)", "Obtain professional indemnity insurance", "Register with health funds (if offering private billing)", "Apply for DVA provider number (if applicable)", "Set up PRODA account for HPOS access"], "mistakes": ["Not realising Medicare provider numbers are location-specific", "Letting AHPRA registration lapse during transition", "Not understanding the difference between NP endorsement types"], "tips": ["Medicare provider numbers take 4-6 weeks — apply early", "Keep a copy of all registration numbers in a secure password manager", "Set calendar reminders 3 months before each renewal date"]}'),
(4, 'business-planning', 'Business Plan & Financial Modelling', 'Revenue models, costs, and break-even', 'Build a realistic financial model, understand your revenue streams, and plan for sustainable growth.', 'Foundation', 'Calculator', 'starter', 4, '{"overview": "A health business without a financial model is flying blind. This phase helps you understand exactly how many patients you need, what to charge, and when you will break even.", "checklist": ["Calculate fixed costs (rent, insurance, software, staff)", "Model revenue per consultation type", "Understand Medicare rebate schedules for your items", "Calculate break-even patient volume", "Plan cash flow for first 12 months", "Identify funding options (savings, loans, grants)"], "mistakes": ["Underestimating how long it takes to build a full patient book", "Not accounting for no-shows and cancellations (typically 10-15%)", "Ignoring the cost of compliance and professional development"], "tips": ["Model three scenarios: conservative, expected, optimistic", "Most practices take 12-18 months to reach profitability", "Keep 6 months of operating expenses in reserve"]}'),
(5, 'location-setup', 'Location & Premises', 'Physical, telehealth, or hybrid setup', 'Choose your practice model, find the right location, and set up a compliant clinical environment.', 'Operations', 'MapPin', 'starter', 5, '{"overview": "Your practice model (physical, telehealth, or hybrid) determines your cost structure, patient reach, and operational complexity.", "checklist": ["Decide on practice model: physical, telehealth, or hybrid", "If physical: find premises with appropriate zoning", "Ensure disability access compliance (DDA)", "Set up clinical areas meeting infection control standards", "Configure waiting area and reception", "Install appropriate signage (check AHPRA rules)"], "mistakes": ["Signing a long lease before validating patient demand", "Not checking council zoning for medical use", "Underestimating fit-out costs for a compliant clinical space"], "tips": ["Telehealth-first is the lowest-risk way to start", "Shared medical suites reduce upfront capital significantly", "Check if your area qualifies for DPA/MM incentives"]}'),
(6, 'technology-stack', 'Technology & Systems', 'PMS, telehealth, communications', 'Choose and configure the right practice management system, telehealth platform, and supporting technology.', 'Operations', 'Monitor', 'starter', 6, '{"overview": "Your technology stack is the backbone of your practice. Choose systems that integrate well, meet compliance requirements, and scale with your growth.", "checklist": ["Select practice management system (Halaxy, Best Practice, Cliniko)", "Set up telehealth platform (if applicable)", "Configure online booking", "Set up secure clinical communications", "Implement backup and disaster recovery", "Choose accounting software (Xero recommended)"], "mistakes": ["Choosing a PMS based on price alone without considering integrations", "Not setting up automatic backups from day one", "Using personal email or phone for patient communications"], "tips": ["Halaxy has the best API and built-in telehealth for NPs", "Always choose Australian-hosted solutions for patient data", "Test your telehealth setup with a colleague before going live"]}'),
(7, 'compliance-governance', 'Compliance & Clinical Governance', 'Policies, procedures, and risk management', 'Establish clinical governance frameworks, write essential policies, and build a culture of compliance.', 'Compliance', 'FileCheck', 'starter', 7, '{"overview": "Clinical governance is not optional — it protects your patients, your registration, and your business. This phase covers the essential policies and procedures every practice needs.", "checklist": ["Write privacy policy (APP compliant)", "Create consent form templates", "Establish clinical governance framework", "Write incident reporting procedure", "Create risk register", "Establish medication management policy (if applicable)", "Set up complaints handling process"], "mistakes": ["Copying another practice privacy policy without customising", "Not having a documented incident reporting process", "Treating clinical governance as a one-off rather than ongoing"], "tips": ["Templates are a starting point — always have a lawyer review", "Review and update policies at least annually", "Train all staff on key policies during onboarding"]}'),
(8, 'billing-payments', 'Billing & Payments', 'Medicare, private billing, and payment systems', 'Set up billing systems, understand Medicare claiming, and configure payment processing for maximum revenue capture.', 'Operations', 'CreditCard', 'starter', 8, '{"overview": "Billing errors are one of the biggest revenue leaks in healthcare. This phase ensures you are billing correctly, claiming accurately, and getting paid on time.", "checklist": ["Understand MBS item numbers for your profession", "Configure Medicare online claiming in your PMS", "Set up EFTPOS/payment terminal", "Configure private billing rates", "Set up payment plans for larger invoices", "Understand bulk billing incentives and restrictions", "Configure automatic payment reminders"], "mistakes": ["Using incorrect MBS item numbers (audit risk)", "Not reconciling Medicare claims weekly", "Bulk billing everything without understanding the financial impact"], "tips": ["Check the MBS Online for item number updates quarterly", "Claim rejections over 5% warrant investigation", "Consider mixed billing: bulk bill concession, private bill others"]}'),
(9, 'staffing-hr', 'Staffing & HR', 'Hiring, contracts, and team management', 'Hire the right team, set up compliant employment contracts, and create a positive workplace culture.', 'Operations', 'Users', 'professional', 9, '{"overview": "Your team can make or break your practice. This phase covers hiring, onboarding, managing, and retaining the right people.", "checklist": ["Determine staffing needs and roles", "Create position descriptions", "Set up employment contracts (Fair Work compliant)", "Register for PAYG withholding", "Set up superannuation", "Create onboarding checklist", "Establish performance review process"], "mistakes": ["Using contractor arrangements when the relationship is really employment", "Not checking AHPRA registration for clinical staff", "Skipping reference checks"], "tips": ["The Health Practitioner Award covers most clinical staff", "Reception staff are often the most important hire — they set the tone", "Invest in training — it is cheaper than recruitment"]}'),
(10, 'marketing-growth', 'Marketing & Patient Acquisition', 'Ethical marketing within AHPRA guidelines', 'Build your patient base through compliant marketing, referral networks, and community engagement.', 'Growth', 'Megaphone', 'starter', 10, '{"overview": "Healthcare marketing has strict rules under AHPRA guidelines. This phase shows you how to grow your patient base ethically and effectively.", "checklist": ["Build a compliant website (no testimonials, no guarantees)", "Set up Google Business Profile", "Create referral networks with other practitioners", "Develop patient education content", "Set up social media presence (within AHPRA rules)", "Consider directory listings (HealthShare, HotDoc)"], "mistakes": ["Using patient testimonials on your website (AHPRA violation)", "Making claims about guaranteed outcomes", "Naming prescription medications in marketing materials"], "tips": ["Educational content is the safest and most effective marketing", "Google Business Profile is free and drives significant local traffic", "Build relationships with GPs who can refer to your specialty"]}'),
(11, 'patient-experience', 'Patient Experience & Retention', 'From first contact to loyal advocate', 'Design every touchpoint of the patient journey to maximise satisfaction, retention, and word-of-mouth referrals.', 'Growth', 'Heart', 'professional', 11, '{"overview": "Acquiring a new patient costs 5-7x more than retaining one. This phase optimises every touchpoint to keep patients coming back and referring others.", "checklist": ["Map the complete patient journey", "Optimise online booking flow", "Create pre-appointment communications", "Design welcoming physical/virtual environment", "Implement post-appointment follow-up", "Set up patient feedback mechanism", "Create recall and reminder systems"], "mistakes": ["Long wait times without communication", "No follow-up after first appointment", "Making it hard to book online"], "tips": ["Send appointment reminders 48h and 2h before", "A simple follow-up SMS after first visit dramatically improves retention", "Ask for Google reviews (not testimonials) to build online presence"]}'),
(12, 'data-analytics', 'Data & Analytics', 'Measure what matters', 'Track key practice metrics, understand your data, and make evidence-based business decisions.', 'Growth', 'BarChart3', 'professional', 12, '{"overview": "What gets measured gets managed. This phase establishes the KPIs that matter for healthcare businesses and shows you how to track them.", "checklist": ["Define key practice KPIs", "Set up financial dashboards", "Track patient acquisition sources", "Monitor no-show and cancellation rates", "Track revenue per practitioner", "Monitor Medicare claim rejection rates", "Review metrics monthly"], "mistakes": ["Tracking vanity metrics instead of actionable ones", "Not reviewing financial data until BAS time", "Ignoring seasonal patterns in patient volume"], "tips": ["Five key metrics: revenue/week, new patients/week, no-show rate, claim rejections, outstanding receivables", "Review dashboard weekly — monthly is too late to catch issues", "Compare your metrics to industry benchmarks"]}'),
(13, 'insurance-risk', 'Insurance & Risk Management', 'Protect your practice and personal assets', 'Ensure comprehensive insurance coverage and implement risk management strategies to protect your business.', 'Compliance', 'Shield', 'professional', 13, '{"overview": "Adequate insurance is non-negotiable in healthcare. This phase covers all the insurance types you need and risk management strategies to minimise claims.", "checklist": ["Professional indemnity insurance (verify coverage limits)", "Public liability insurance", "Business insurance (contents, equipment)", "Cyber insurance (increasingly important)", "Workers compensation (if employing staff)", "Income protection insurance", "Review insurance annually"], "mistakes": ["Assuming professional indemnity covers everything", "Not declaring telehealth activities to insurer", "Underinsuring equipment and fit-out"], "tips": ["Bundle policies for better rates", "Cyber insurance is essential if you store patient data electronically", "Always disclose new services to your insurer"]}'),
(14, 'telehealth-setup', 'Telehealth Operations', 'Setup, MBS items, and best practices', 'Establish compliant telehealth services with the right technology, billing practices, and patient experience.', 'Operations', 'Video', 'starter', 14, '{"overview": "Telehealth is now a permanent part of Australian healthcare. This phase covers setup, billing, compliance, and best practices for effective telehealth delivery.", "checklist": ["Choose telehealth platform (must be end-to-end encrypted)", "Understand telehealth MBS item numbers for your profession", "Set up compliant consent for telehealth", "Configure virtual waiting room", "Test audio/video quality and backup plans", "Understand geographic eligibility rules", "Set up telehealth-specific clinical protocols"], "mistakes": ["Not verifying patient identity before telehealth consultations", "Using non-encrypted platforms (Zoom basic, FaceTime)", "Billing telehealth items without meeting the existing relationship rules"], "tips": ["Halaxy has built-in telehealth that meets all requirements", "Always have a phone backup plan for technology failures", "Document that consultation was via telehealth in clinical notes"]}'),
(15, 'clinical-excellence', 'Clinical Excellence & CPD', 'Evidence-based care and continuous learning', 'Maintain clinical excellence through evidence-based practice, continuous professional development, and quality improvement.', 'Clinical', 'GraduationCap', 'professional', 15, '{"overview": "Your clinical skills are your primary asset. This phase ensures you maintain excellence through structured CPD, evidence-based practice, and quality improvement.", "checklist": ["Set up CPD tracking system", "Join relevant professional associations", "Subscribe to key clinical journals/resources", "Establish clinical audit process", "Create peer review arrangements", "Plan annual CPD budget", "Document all CPD activities for AHPRA"], "mistakes": ["Leaving CPD tracking until registration renewal", "Only doing free CPD without strategic focus", "Not documenting informal learning activities"], "tips": ["AHPRA requires minimum 20 CPD hours/year for most professions", "Mix CPD types: conferences, online, peer review, clinical audit", "Keep a CPD diary — update it monthly, not annually"]}'),
(16, 'mental-health-wellbeing', 'Practitioner Wellbeing', 'Prevent burnout before it starts', 'Protect your own mental health and wellbeing as a healthcare business owner — because you cannot pour from an empty cup.', 'Clinical', 'HeartPulse', 'free', 16, '{"overview": "Healthcare practitioner burnout is epidemic. This phase is about building sustainable practices that protect your wellbeing while running a successful business.", "checklist": ["Set sustainable work hours and boundaries", "Arrange regular clinical supervision", "Establish peer support network", "Create leave and coverage plans", "Set up workplace health and safety", "Plan regular breaks and holidays", "Know the signs of burnout and have an action plan"], "mistakes": ["Working 60+ hour weeks to build the practice quickly", "Not having anyone to debrief with after difficult cases", "Ignoring early burnout signs"], "tips": ["Schedule your own appointments first — they are non-negotiable", "Peer supervision groups are free and invaluable", "Consider a coach or mentor who understands healthcare businesses"]}'),
(17, 'scaling-growth', 'Scaling & Growth', 'From solo to multi-practitioner', 'Plan and execute your growth strategy — whether that is adding practitioners, locations, or services.', 'Growth', 'TrendingUp', 'professional', 17, '{"overview": "Growing from solo practitioner to practice owner is a significant mindset shift. This phase covers the strategic and operational aspects of scaling.", "checklist": ["Define growth strategy (practitioners, locations, services)", "Create practitioner onboarding process", "Establish clinical governance for multi-practitioner model", "Set up revenue sharing or employment models", "Plan space and technology for growth", "Build management capability", "Create standard operating procedures"], "mistakes": ["Growing too fast without the systems to support it", "Not having clear service agreements with associate practitioners", "Assuming more practitioners automatically means more profit"], "tips": ["Add one practitioner at a time and stabilise before adding another", "SOPs are essential — document everything before you need to delegate", "Your role shifts from clinician to manager — plan for that transition"]}'),
(18, 'partnerships-referrals', 'Partnerships & Referral Networks', 'Build your professional ecosystem', 'Develop strategic partnerships, referral pathways, and professional networks that drive sustainable growth.', 'Growth', 'Handshake', 'professional', 18, '{"overview": "No health practice exists in isolation. Strong referral networks and partnerships are essential for patient care and business growth.", "checklist": ["Identify key referral sources for your specialty", "Create referral pathways and acknowledgement processes", "Join local health networks and PHNs", "Develop relationships with allied health providers", "Consider co-location or shared care arrangements", "Set up referral tracking in your PMS"], "mistakes": ["Expecting referrals without building relationships first", "Not acknowledging referrals promptly", "Only referring within your own practice"], "tips": ["A personal visit to a GP practice is worth 100 emails", "Acknowledge every referral within 48 hours with a brief update", "Cross-referral arrangements benefit both practices"]}'),
(19, 'financial-optimisation', 'Financial Optimisation', 'Tax planning, superannuation, and wealth building', 'Optimise your financial position through smart tax planning, superannuation strategies, and business structure review.', 'Finance', 'PiggyBank', 'professional', 19, '{"overview": "Healthcare professionals often under-optimise their financial position. This phase covers tax planning, superannuation, and wealth building strategies specific to health businesses.", "checklist": ["Review business structure with health-specialist accountant", "Optimise salary vs dividend mix", "Maximise superannuation contributions", "Review depreciation schedule for equipment", "Set up BAS and tax payment schedule", "Consider income protection and key person insurance", "Plan for practice valuation and succession"], "mistakes": ["Not claiming all eligible deductions", "Mixing personal and business expenses", "Not planning for GST and tax payments quarterly"], "tips": ["A health-specialist accountant typically saves 3-5x their fee", "Prepaying expenses before 30 June can significantly reduce tax", "Review your structure every 2-3 years as circumstances change"]}'),
(20, 'digital-presence', 'Digital Presence & SEO', 'Be found by the right patients', 'Build a strong digital presence that attracts patients while remaining compliant with AHPRA advertising guidelines.', 'Growth', 'Globe', 'starter', 20, '{"overview": "Most patients find their healthcare providers online. This phase ensures you are visible, credible, and compliant in the digital space.", "checklist": ["Build a professional, AHPRA-compliant website", "Optimise Google Business Profile", "Implement local SEO strategy", "Create educational content strategy", "Set up directory listings", "Monitor online reputation", "Ensure website accessibility (WCAG AA)"], "mistakes": ["Having no website at all", "Using stock photos of American clinics", "Writing content that makes health claims without evidence"], "tips": ["Google Business Profile is the single most important listing", "Blog posts answering common patient questions drive organic traffic", "Use real photos of your practice and team (with consent)"]}'),
(21, 'accreditation', 'Accreditation & Standards', 'Meet and exceed industry standards', 'Achieve relevant accreditations and maintain ongoing compliance with industry standards.', 'Compliance', 'Award', 'practice', 21, '{"overview": "Accreditation demonstrates your commitment to quality and may be required for certain funding or insurance panels.", "checklist": ["Identify relevant accreditation bodies for your profession", "Review accreditation standards and requirements", "Conduct gap analysis against standards", "Prepare documentation for accreditation", "Schedule accreditation assessment", "Implement continuous quality improvement", "Plan for re-accreditation cycle"], "mistakes": ["Treating accreditation as a one-off event", "Not maintaining documentation between assessments", "Underestimating the time required for preparation"], "tips": ["Start preparation 6-12 months before assessment", "Assign an accreditation coordinator", "Use the standards as a framework for ongoing quality improvement"]}'),
(22, 'innovation-research', 'Innovation & Research', 'Stay ahead of the curve', 'Explore innovation opportunities, research participation, and emerging models of care.', 'Growth', 'Microscope', 'practice', 22, '{"overview": "Healthcare is rapidly evolving. This phase helps you identify and adopt innovations that improve patient care and business sustainability.", "checklist": ["Monitor emerging healthcare technologies", "Explore AI-assisted clinical tools", "Consider research participation opportunities", "Evaluate new models of care", "Assess remote patient monitoring options", "Stay current with digital health standards", "Network with innovation-focused peers"], "mistakes": ["Adopting technology for its own sake without clear patient benefit", "Ignoring AI and digital health developments", "Not evaluating the evidence before implementing new approaches"], "tips": ["Join your PHN innovation network", "Start small — pilot new approaches with a subset of patients", "Document outcomes to build your own evidence base"]}'),
(23, 'succession-exit', 'Succession & Exit Planning', 'Build a business that can thrive without you', 'Plan for your eventual exit — whether that is selling, transitioning, or closing your practice.', 'Finance', 'DoorOpen', 'practice', 23, '{"overview": "Every business owner should have an exit plan, even if exit is decades away. Planning early maximises practice value and ensures continuity of patient care.", "checklist": ["Determine your ideal exit timeline and scenario", "Get a practice valuation", "Document all processes and SOPs", "Build a management team that can operate without you", "Review legal structure for sale readiness", "Plan patient transition strategy", "Consider earn-out vs clean sale structures"], "mistakes": ["Waiting until burnout to think about succession", "Having a practice that is entirely dependent on you personally", "Not maintaining clean financial records for due diligence"], "tips": ["A practice with documented systems sells for 2-3x more", "Start building your exit plan at least 5 years before", "Introduce potential successors to patients gradually"]}'),
(24, 'legacy-impact', 'Legacy & Impact', 'Beyond the business — your broader contribution', 'Consider your broader impact on healthcare, community, and the profession.', 'Growth', 'Sparkles', 'free', 24, '{"overview": "As an established healthcare business owner, you have the opportunity to shape the future of healthcare in your community and profession.", "checklist": ["Mentor emerging practitioners", "Contribute to professional associations", "Participate in policy and advocacy", "Share knowledge through teaching or publishing", "Support healthcare access in underserved areas", "Build a sustainable practice model others can learn from", "Document and share your journey"], "mistakes": ["Getting so caught up in business that you forget why you started", "Not giving back to the profession that supported your growth", "Isolating yourself from the broader healthcare community"], "tips": ["Mentoring is one of the most rewarding things you can do", "Even small advocacy efforts can create meaningful policy change", "Your experience is valuable — share it"]}');
